# $ = Recursos estáticos
# ! = Paquetes

*: /{_pack}/_services/{_svc?} > ${_pack}/_services/{_svc}
*: /{_pack}/_services/{_program}/{_svc?} > ${_pack}/_services/{_program}/{_svc}

*: /!/{_pack}/{_program}/{_entity_id}/{_view?}/ > ${_pack}/entry-point.dkl
*: /!/{_pack}/{_program}/{_entity_id?}/ > ${_pack}/entry-point.dkl
*: /!/{_pack}/ > ${_pack}/index.dkl

*: /$/{_pack}/{_level1}/{_level2}/{_resource} > ${_pack}/_static/{_level1}/{_level2}/{_resource}
*: /$/{_pack}/{_level1}/{_resource} > ${_pack}/_static/{_level1}/{_resource}
*: /$/{_pack}/{_resource} > ${_pack}/_static/{_resource}

*: / > $webshell/index.dkl
*: /webshell/frontpage.dkl > $webshell/frontpage.dkl